import React, { useMemo } from 'react';
import { View, Text, StyleSheet, TouchableOpacity, useWindowDimensions } from 'react-native';
import { LinearGradient } from 'expo-linear-gradient';
import { COLORS, FONT, GRADIENTS, RADIUS } from '../constants/theme';
import type { CategoryKey } from '../types';

type IconComponent = React.ComponentType<{ size: number; color: string }>;

interface CategoryPillProps {
  label: CategoryKey;
  icon?: IconComponent;
  isActive: boolean;
  onPress: (label: CategoryKey) => void;
}

/** Figma: 28pt icon in 48–50pt pills at 390pt baseline */
const ICON_BASE = 28;

export function CategoryPill({ label, icon: Icon, isActive, onPress }: CategoryPillProps) {
  const { width } = useWindowDimensions();
  const scale = width / 390;

  const sx = useMemo(
    () => ({
      up:    20 * scale,
      blur:  30 * scale,
      r:     RADIUS.md * scale,
      icon:  ICON_BASE * scale,
      fs:    13 * scale,
      wAct:  48 * scale,
      hAct:  48 * scale,
      wIn:   50 * scale,
      hIn:   50 * scale,
    }),
    [scale],
  );

  const glowWrap = {
    shadowColor: '#2b3445' as const,
    shadowOffset: { width: 0, height: -sx.up },
    shadowOpacity: 0.5,
    shadowRadius: sx.blur,
    elevation: 0 as const,
  };

  const dropBelow = {
    shadowColor: '#10141c' as const,
    shadowOffset: { width: 0, height: sx.up },
    shadowOpacity: 1,
    shadowRadius: sx.blur,
  };

  if (isActive) {
    return (
      <View style={glowWrap}>
        <TouchableOpacity onPress={() => onPress(label)} activeOpacity={0.85}>
          <LinearGradient
            colors={GRADIENTS.accent}
            start={{ x: 0, y: 0 }}
            end={{ x: 1, y: 1 }}
            style={[
              styles.pillBase,
              {
                width: sx.wAct,
                height: sx.hAct,
                borderRadius: sx.r,
                ...dropBelow,
                elevation: 14,
              },
            ]}
          >
            {Icon ? (
              <Icon size={sx.icon} color={COLORS.white} />
            ) : (
              <Text style={[styles.labelActive, { fontSize: sx.fs }]}>{label}</Text>
            )}
          </LinearGradient>
        </TouchableOpacity>
      </View>
    );
  }

  // Inactive pill uses same dark gradient as card backgrounds (Figma: #353f54 → #222834)
  return (
    <View style={glowWrap}>
      <TouchableOpacity onPress={() => onPress(label)} activeOpacity={0.85}>
        <LinearGradient
          colors={['#353f54', '#222834']}
          start={{ x: 0.3, y: 0 }}
          end={{ x: 0, y: 1 }}
          style={[
            styles.pillBase,
            {
              width: sx.wIn,
              height: sx.hIn,
